// 1. Obtener el texto correcto
const raw = $json.content.parts[0].text;

// 2. Limpiar ```json
const cleaned = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// 3. Parsear JSON
const parsed = JSON.parse(cleaned);

// 4. Mapear al formato que querés
const result = parsed.map(item => ({
  text: item.text || "",
  summary: item.summary || "",
  keywords: item.keywords || [],
  source: item.source || "",
  chunk_index: item.chunk_index ?? 0,
  chunk_id: item.chunk_id || ""
}));

// 5. Output n8n
return result.map(r => ({ json: r }));

const items = $input.all();

// Caso 1: múltiples items (lo más común en n8n)
if (items.length > 1) {
  return items.map((item, index) => {
    const d = item.json;

    return {
      json: {
        text: `ID: ${d.ID}, Nombre: ${d.Nombre}, Edad: ${d.Edad}, Pais: ${d.Pais}, IngresoMensual: ${d.IngresoMensual}`,
        source: "ejemplo_datos",
        chunk_index: index,
        chunk_id: `ejemplo_datos_${index}`
      }
    };
  });
}

// Caso 2: un solo item con array adentro
let data = items[0].json;

// si viene como { data: [...] }
if (Array.isArray(data.data)) {
  data = data.data;
}

// si viene como array directo
else if (Array.isArray(data)) {
  // ok
}

// si viene como objeto único
else {
  data = [data];
}

return data.map((item, index) => {
  return {
    json: {
      text: `ID: ${item.ID}, Nombre: ${item.Nombre}, Edad: ${item.Edad}, Pais: ${item.Pais}, IngresoMensual: ${item.IngresoMensual}`,
      source: "ejemplo_datos",
      chunk_index: index,
      chunk_id: `ejemplo_datos_${index}`
    }
  };
});

// --- EMBEDDING RESPUESTA (CORREGIDO) ---
const responseItem = $items("Vectorizador respuesta", 0, 0)[0];
const responseEmbedding = responseItem.json.embedding.values;

// --- EMBEDDINGS FRAGMENTOS ---
const fragmentItems = $items("Vectorizacion fragmentos", 0);
const fragmentEmbeddings = fragmentItems.map(item => item.json.embedding.values);

// --- COSINE SIMILARITY ---
function cosineSimilarity(a, b) {
    if (!a || !b || a.length !== b.length) return 0;

    let dot = 0, normA = 0, normB = 0;

    for (let i = 0; i < a.length; i++) {
        dot += a[i] * b[i];
        normA += a[i] * a[i];
        normB += b[i] * b[i];
    }

    if (normA === 0 || normB === 0) return 0;

    return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

// --- 1. SIMILITUDES ---
const similarities = fragmentEmbeddings.map(f =>
    cosineSimilarity(responseEmbedding, f)
);

// --- 2. TOP-K ---
const K = 3;
const sorted = [...similarities].sort((a, b) => b - a);
const topK = sorted.slice(0, K);

// --- 3. PROMEDIO TOP-K ---
const avgTopK = topK.reduce((a, b) => a + b, 0) / topK.length;

// --- 4. BONUS POR CONSISTENCIA ---
const strongMatches = similarities.filter(s => s > 0.75).length;
const consistencyBonus = Math.min(strongMatches * 0.02, 0.05);

// --- 5. SCORE FINAL ---
const finalScore = Math.min(avgTopK + consistencyBonus, 1);

// --- OUTPUT ---
return [
  {
    json: {
      finalScore,
      avgTopK,
      consistencyBonus,
      similarities,
      topK,
      fragmentCount: similarities.length
    }
  }
];

// Obtener almacenamiento global del workflow
const globalData = $getWorkflowStaticData('global');

// Inicializar si no existe
if (globalData.counter === undefined) {
  globalData.counter = 0;
}

// Incrementar contador
globalData.counter += 1;

// Devolver resultado
return items.map(item => ({
  json: {
    ...item.json,
    counter: globalData.counter
  }
}));

// Acceder al almacenamiento global del workflow
const globalData = $getWorkflowStaticData('global');

// Resetear contador
globalData.counter = 0;

// (Opcional) devolver info para debug
return items.map(item => ({
  json: {
    ...item.json,
    counter: globalData.counter,
    message: "Counter reseteado a 0"
  }
}));

